package adminbatchverifyapikeys

import (
	"context"
	"fmt"

	client "github.com/ory/talos-client-go"
)

func batchVerifyAPIKeys(ctx context.Context, c *client.APIClient, credentials []string) error {
	requests := make([]client.V2alpha1VerifyAPIKeyRequest, len(credentials))
	for i, cred := range credentials {
		requests[i] = client.V2alpha1VerifyAPIKeyRequest{
			Credential: client.PtrString(cred),
		}
	}

	resp, _, err := c.StaticCredentialsAPI.
		AdminBatchVerifyAPIKeys(ctx).
		V2alpha1BatchVerifyAPIKeysRequest(client.V2alpha1BatchVerifyAPIKeysRequest{
			Requests: requests,
		}).
		Execute()
	if err != nil {
		return fmt.Errorf("batch verify: %w", err)
	}

	for i, r := range resp.Results {
		fmt.Printf("[%d] active=%v key_id=%s\n", i, r.GetIsActive(), r.GetKeyId())
	}
	return nil
}

