package adminderivetoken

import (
	"context"
	"fmt"

	client "github.com/ory/talos-client-go"
)

func deriveToken(ctx context.Context, c *client.APIClient, credential string) error {
	algo := client.V2ALPHA1TOKENALGORITHM_TOKEN_ALGORITHM_JWT
	resp, _, err := c.StaticCredentialsAPI.
		AdminDeriveToken(ctx).
		V2alpha1DeriveTokenRequest(client.V2alpha1DeriveTokenRequest{
			Credential: client.PtrString(credential),
			Algorithm:  &algo,
			Ttl:        client.PtrString("1h"),
			Scopes:     []string{"read"},
		}).
		Execute()
	if err != nil {
		return fmt.Errorf("derive token: %w", err)
	}

	fmt.Println("Token:", resp.GetToken().GetToken())
	return nil
}

