package adminverifyapikey

import (
	"context"
	"fmt"

	client "github.com/ory/talos-client-go"
)

func verifyAPIKey(ctx context.Context, c *client.APIClient, credential string) error {
	resp, _, err := c.StaticCredentialsAPI.
		AdminVerifyAPIKey(ctx).
		V2alpha1VerifyAPIKeyRequest(client.V2alpha1VerifyAPIKeyRequest{
			Credential: client.PtrString(credential),
		}).
		Execute()
	if err != nil {
		return fmt.Errorf("verify key: %w", err)
	}

	if !resp.GetIsActive() {
		fmt.Println("Inactive:", resp.GetErrorMessage())
		return nil
	}
	fmt.Println("Active key:", resp.GetKeyId(), "actor:", resp.GetActorId(), "scopes:", resp.Scopes)
	return nil
}

