func issueAPIKey(ctx context.Context, c *client.APIClient) error {
	resp, _, err := c.StaticCredentialsAPI.
		AdminIssueAPIKey(ctx).
		V2alpha1IssueAPIKeyRequest(client.V2alpha1IssueAPIKeyRequest{
			Name:    client.PtrString("my-service"),
			ActorId: client.PtrString("user_123"),
			Scopes:  []string{"read", "write"},
			Ttl:     client.PtrString("720h"),
		}).
		Execute()
	if err != nil {
		return fmt.Errorf("issue key: %w", err)
	}

	// Secret is returned only once; store it now.
	fmt.Println("Key ID:", resp.GetIssuedApiKey().GetKeyId())
	fmt.Println("Secret:", resp.GetSecret())
	return nil
}

