import (
	"context"
	"fmt"

	client "github.com/ory/talos-client-go"
)

func selfRevokeAPIKey(ctx context.Context, c *client.APIClient, credential string) error {
	reason := client.V2ALPHA1REVOCATIONREASON_REVOCATION_REASON_KEY_COMPROMISE
	if _, _, err := c.SelfServiceAPI.
		RevokeAPIKey(ctx).
		V2alpha1SelfRevokeAPIKeyRequest(client.V2alpha1SelfRevokeAPIKeyRequest{
			Credential: client.PtrString(credential),
			Reason:     &reason,
		}).
		Execute(); err != nil {
		return fmt.Errorf("self-revoke key: %w", err)
	}

	fmt.Println("Self-revoked successfully.")
	return nil
}
